sys_script_include.script:
var IncentNowSystemConfigUtil = Class.create();
IncentNowSystemConfigUtil.prototype = {

    initialize: function() {

        this.UNITS = {
            CURRENCY: 'currency',
            PERCENTAGE: 'percentage'
        };

        // Apply defaults ONLY if empty/null

        this.currencySymbol = this._getProp('x_ctans_incentnow.currency_symbol', this._getSystemCurrencySymbol());
        this.currencyPosition = this._getProp('x_ctans_incentnow.currency_position', 'before');

        var dp = this._getProp('x_ctans_incentnow.decimal_places', '2');
        this.decimalPlaces = parseInt(dp, 10);
        if (isNaN(this.decimalPlaces)) {
            this.decimalPlaces = 2;
        }

        this.useThousandsSeparator = this._getProp('x_ctans_incentnow.thousand_separator', 'true') == 'true';
    },

    // -----------------------------------------
    // FORMATTERS
    // -----------------------------------------

    formatCurrency: function(value) {

        var val = parseFloat(value) || 0;

        val = this._formatSmartDecimal(val);

        if (this.useThousandsSeparator) {
            val = this._addThousandsSeparator(val);
        }

        if (this.currencyPosition == 'before') {
            return this.currencySymbol + val;
        } else {
            return val + ' ' + this.currencySymbol;
        }
    },

    formatPercentage: function(value) {
        var val = parseFloat(value) || 0;
        val = this._formatSmartDecimal(val);
        return val + '%';
    },

    formatNumber: function(value) {
        var val = parseFloat(value) || 0;
        return this._formatSmartDecimal(val);
    },

    format: function(value, unit) {

        if (unit == this.UNITS.CURRENCY) {
            return this.formatCurrency(value);
        }

        if (unit == this.UNITS.PERCENTAGE) {
            return this.formatPercentage(value);
        }

        return this.formatNumber(value);
    },

    // -----------------------------------------
    // HELPERS
    // -----------------------------------------

    // Smart decimal handling
    _formatSmartDecimal: function(val) {

        var fixed = val.toFixed(this.decimalPlaces);

        // Remove trailing .00 or .0
        if (parseFloat(fixed) == parseInt(fixed, 10)) {
            return parseInt(fixed, 10).toString();
        }

        return fixed;
    },

    //  Property fallback only when empty/null
    _getProp: function(name, defaultValue) {

        var val = gs.getProperty(name);

        if (val === null || val === undefined || val === '') {
            return defaultValue;
        }

        return val;
    },

    _addThousandsSeparator: function(numStr) {
        return numStr.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    },

	_getSystemCurrencySymbol: function() {

    var currencyCode = gs.getProperty('glide.i18n.single_currency.code', 'USD');

    var currencyGR = new GlideRecordSecure('fx_currency');
    currencyGR.addQuery('code', currencyCode);
    currencyGR.addQuery('active', true);
    currencyGR.setLimit(1);
    currencyGR.query();

    if (currencyGR.next()) {
        return currencyGR.getValue('symbol') || currencyCode;
    }

    return currencyCode;
},

    type: 'IncentNowSystemConfigUtil'
};
